SELECT COUNT(DISTINCT s.pk_siape) AS qtd_servidores FROM servidor s JOIN calc_hora_aula_media c ON c.siape = s.pk_siape WHERE LOWER(s.sigla_campus) = LOWER('gyn') AND LOWER(s.area_ingresso) = LOWER('biologia geral') AND LOWER(s.contrato) = LOWER('efetivos') AND c.ano = 2022 AND c.semestre = 2 AND s.saiu_do_ifg = FALSE